import{_ as e,o as a,c as r,a2 as d}from"./chunks/framework.c3r8iWL8.js";const p=JSON.parse('{"title":"Guide: Data Governance Layers","description":"Reference template for AI-native enterprise delivery on AWS","frontmatter":{},"headers":[],"relativePath":"guides/data-governance.md","filePath":"guides/data-governance.md","lastUpdated":1782929962000}'),o={name:"guides/data-governance.md"};function n(i,t,s,l,c,g){return a(),r("div",null,[...t[0]||(t[0]=[d('<h1 id="guide-data-governance-layers" tabindex="-1">Guide: Data Governance Layers <a class="header-anchor" href="#guide-data-governance-layers" aria-label="Permalink to &quot;Guide: Data Governance Layers&quot;">​</a></h1><p><strong>Decision:</strong> How to classify, control, retain, and trace data — including what may enter AI prompts and RAG indexes.</p><p>Related: <a href="./../data-governance.html">data-governance.md</a> · <a href="./ai-guardrails-security.html">ai-guardrails-security.md</a> · <a href="./../sops/SOP-010-ai-tool-usage.html">SOP-010</a> · <a href="./monitoring-tracing-logging.html">monitoring-tracing-logging.md</a></p><hr><h2 id="layer-1-—-classification-catalog" tabindex="-1">Layer 1 — Classification &amp; catalog <a class="header-anchor" href="#layer-1-—-classification-catalog" aria-label="Permalink to &quot;Layer 1 — Classification &amp; catalog&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Approach</th><th>Pros</th><th>Cons</th></tr></thead><tbody><tr><td><strong>Manual labels in catalog (Glue, Collibra, Atlan)</strong></td><td>Business-owned definitions</td><td>Drift if not enforced in code</td></tr><tr><td><strong>Automated classification (Macie, Microsoft Purview)</strong></td><td>Finds PII in S3/RDS</td><td>False positives; tuning</td></tr><tr><td><strong>Tag-based (AWS resource tags + ABAC)</strong></td><td>Policy-enforceable</td><td>Tag hygiene required</td></tr><tr><td><strong>Schema annotations (OpenAPI <code>x-classification</code>)</strong></td><td>Close to API contract</td><td>Only covers declared fields</td></tr></tbody></table><p><strong>Recommended:</strong> Combine schema annotations for APIs + Macie for object stores + steward-owned catalog glossary.</p><h3 id="classification-tiers-example" tabindex="-1">Classification tiers (example) <a class="header-anchor" href="#classification-tiers-example" aria-label="Permalink to &quot;Classification tiers (example)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Tier</th><th>Examples</th><th>AI prompt</th><th>RAG index</th><th>Log/trace</th></tr></thead><tbody><tr><td><strong>Public</strong></td><td>Marketing copy</td><td>Allowed</td><td>Allowed</td><td>Allowed</td></tr><tr><td><strong>Internal</strong></td><td>Internal APIs docs</td><td>Enterprise AI only</td><td>Internal index</td><td>Allowed masked</td></tr><tr><td><strong>Confified</strong></td><td>Customer metadata</td><td>Deny by default</td><td>Separate restricted index</td><td>Redact fields</td></tr><tr><td><strong>Restricted</strong></td><td>PII, PCI, PHI</td><td><strong>Never</strong></td><td><strong>Never</strong> without legal sign-off</td><td>Never log raw</td></tr></tbody></table><hr><h2 id="layer-2-—-access-control" tabindex="-1">Layer 2 — Access control <a class="header-anchor" href="#layer-2-—-access-control" aria-label="Permalink to &quot;Layer 2 — Access control&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Tool</th><th>Scope</th><th>Pros</th><th>Cons</th></tr></thead><tbody><tr><td><strong>IAM</strong></td><td>AWS resources</td><td>Universal on AWS</td><td>Coarse without ABAC</td></tr><tr><td><strong>Lake Formation</strong></td><td>Data lake tables</td><td>Fine-grained LF-tags</td><td>Lake-centric</td></tr><tr><td><strong>Row/column security (RDS, Redshift)</strong></td><td>Database</td><td>Strong for SQL</td><td>Per-engine setup</td></tr><tr><td><strong>VPC + PrivateLink</strong></td><td>Network path</td><td>Data doesn&#39;t traverse public internet</td><td>Complexity</td></tr><tr><td><strong>KMS CMK per tier</strong></td><td>Encryption keys</td><td>Audit via CloudTrail</td><td>Key management overhead</td></tr></tbody></table><p><strong>Pitfall:</strong> AI-generated SQL or queries bypass app-layer checks → use least-privilege DB roles + query audit.</p><p>→ Full IAM, RBAC, secrets, and CI OIDC patterns: <a href="./identity-access-secrets.html">Guide: Identity, access &amp; secrets</a>.</p><hr><h2 id="layer-3-—-retention-deletion" tabindex="-1">Layer 3 — Retention &amp; deletion <a class="header-anchor" href="#layer-3-—-retention-deletion" aria-label="Permalink to &quot;Layer 3 — Retention &amp; deletion&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Approach</th><th>Pros</th><th>Cons</th></tr></thead><tbody><tr><td><strong>S3 lifecycle rules</strong></td><td>Automatic tier/expire</td><td>Misconfigured rule deletes early</td></tr><tr><td><strong>CloudWatch log retention</strong></td><td>Simple per group</td><td>Easy to set too long (cost + compliance)</td></tr><tr><td><strong>Legal hold (S3 Object Lock)</strong></td><td>Litigation ready</td><td>Blocks deletion</td></tr><tr><td><strong>Right-to-erasure workflow</strong></td><td>GDPR compliance</td><td>Must map all copies (backups, indexes)</td></tr></tbody></table><p><strong>With AI/RAG:</strong> Embeddings and vector stores are <strong>copies</strong> — deletion must include index purge, not just source S3.</p><hr><h2 id="layer-4-—-lineage-quality" tabindex="-1">Layer 4 — Lineage &amp; quality <a class="header-anchor" href="#layer-4-—-lineage-quality" aria-label="Permalink to &quot;Layer 4 — Lineage &amp; quality&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Tool</th><th>Purpose</th><th>Pros</th><th>Cons</th></tr></thead><tbody><tr><td><strong>OpenLineage / Marquez</strong></td><td>Pipeline lineage</td><td>Open standard</td><td>Requires instrumentation</td></tr><tr><td><strong>AWS Glue Data Catalog</strong></td><td>AWS-native metadata</td><td>Integrated with Athena/Glue jobs</td><td>AWS-centric</td></tr><tr><td><strong>Great Expectations / Soda</strong></td><td>Data quality checks</td><td>Catches bad AI training inputs</td><td>Another pipeline stage</td></tr><tr><td><strong>dbt tests</strong></td><td>Transform layer QA</td><td>Dev-friendly</td><td>Warehouse-specific</td></tr></tbody></table><p><strong>Pitfall:</strong> AI generates ETL without documenting lineage → require ADR + lineage emit on new pipelines.</p><hr><h2 id="layer-5-—-ai-specific-governance" tabindex="-1">Layer 5 — AI-specific governance <a class="header-anchor" href="#layer-5-—-ai-specific-governance" aria-label="Permalink to &quot;Layer 5 — AI-specific governance&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Control</th><th>Purpose</th><th>Options</th></tr></thead><tbody><tr><td><strong>Prompt boundary</strong></td><td>Block restricted data in models</td><td>Gateway proxy, DLP on egress</td></tr><tr><td><strong>RAG scope</strong></td><td>Index only approved docs</td><td>Separate indexes by classification</td></tr><tr><td><strong>Training prohibition</strong></td><td>Enterprise contract</td><td>Cursor/Q/Bedrock enterprise tiers</td></tr><tr><td><strong>Synthetic data</strong></td><td>Dev and test</td><td>Faker, Gretel, domain fixtures</td></tr><tr><td><strong>Audit log</strong></td><td>Who prompted what</td><td>Bedrock logging, gateway logs</td></tr></tbody></table><p>Cross-reference <a href="./../sops/SOP-010-ai-tool-usage.html">SOP-010</a>.</p><hr><h2 id="aws-services-map-reference" tabindex="-1">AWS services map (reference) <a class="header-anchor" href="#aws-services-map-reference" aria-label="Permalink to &quot;AWS services map (reference)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Concern</th><th>AWS services</th></tr></thead><tbody><tr><td>Discover PII</td><td>Macie, GuardDuty ( exfil patterns )</td></tr><tr><td>Catalog</td><td>Glue Data Catalog, DataZone</td></tr><tr><td>Lake access</td><td>Lake Formation</td></tr><tr><td>Encryption</td><td>KMS, SSE-S3, TLS</td></tr><tr><td>Audit</td><td>CloudTrail, CloudTrail Lake</td></tr><tr><td>DLP patterns</td><td>Macie custom data identifiers</td></tr><tr><td>Backup retention</td><td>AWS Backup with locked vaults</td></tr></tbody></table><p>Third-party: Collibra, Alation, Immuta, BigID — when enterprise data office already standardized.</p><hr><h2 id="pitfalls" tabindex="-1">Pitfalls <a class="header-anchor" href="#pitfalls" aria-label="Permalink to &quot;Pitfalls&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Pitfall</th><th>Why it hurts</th><th>Mitigation</th></tr></thead><tbody><tr><td><strong>Prod snapshot in dev</strong></td><td>Compliance breach</td><td>Synthetic fixtures only</td></tr><tr><td><strong>Full JSON bodies in logs</strong></td><td>PII in CloudWatch</td><td>Redact + allowlist fields</td></tr><tr><td><strong>Single RAG index for all docs</strong></td><td>Restricted text in agent context</td><td>Split indexes by classification</td></tr><tr><td><strong>AI summarizes customer ticket with PII</strong></td><td>Prompt leak</td><td>Ticket scrubbing before AI</td></tr><tr><td><strong>Retention &quot;forever&quot; on logs</strong></td><td>Cost + legal exposure</td><td>Tier-based retention ADR</td></tr><tr><td><strong>Classification without enforcement</strong></td><td>Labels ignored</td><td>OPA/IAM/Macie alerts</td></tr><tr><td><strong>Forgotten vector embeddings</strong></td><td>Erasure requests fail</td><td>Index lifecycle tied to source</td></tr><tr><td><strong>Cross-border inference</strong></td><td>Regulatory violation</td><td>Region-pinned Bedrock, data residency ADR</td></tr></tbody></table><hr><h2 id="recommended-starting-point" tabindex="-1">Recommended starting point <a class="header-anchor" href="#recommended-starting-point" aria-label="Permalink to &quot;Recommended starting point&quot;">​</a></h2><ol><li>Define 4-tier classification glossary (steward-owned)</li><li>Macie on S3 + secret/PII patterns in CI logs</li><li>OpenAPI field classification for external APIs</li><li>Separate RAG indexes: internal vs restricted (restricted = none for coding agents)</li><li>CloudTrail + Bedrock invocation logging</li><li>Retention ADR per data domain</li></ol><p>Record choices in <strong>your</strong> project&#39;s ADRs.</p><hr><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./knowledge-indexing-portals.html">Knowledge indexing &amp; portals</a> · <a href="./monitoring-tracing-logging.html">Monitoring &amp; tracing</a> · <a href="./incident-management.html">Incident management</a></li></ul>',40)])])}const u=e(o,[["render",n]]);export{p as __pageData,u as default};
